import os
import logging
import azure.functions as func
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.eventgrid.models import EventGridEvent
from azure.identity import ManagedIdentityCredential

credential = ManagedIdentityCredential()
blob_service_client = BlobServiceClient(account_url=os.getenv("AZURE_STORAGE_ACCOUNT_URL"), credential=credential)
cosmos_client = CosmosClient(url=os.getenv("COSMOS_DB_URL"), credential=credential)
event_grid_client = EventGridPublisherClient(endpoint=os.getenv("EVENT_GRID_ENDPOINT"), credential=credential)

database_name = os.getenv("COSMOS_DB_DATABASE_NAME")
container_name = os.getenv("COSMOS_DB_CONTAINER_NAME")

def main(event: func.EventGridEvent):
    logging.info("Received event: %s", event.id)

    blob_url = event.data.get('url')

    # Process Blob
    blob_client = blob_service_client.get_blob_client(container='my-container', blob=blob_url)
    blob_data = blob_client.download_blob().readall()
    
    # Perform some processing and generate results
    results = process_data(blob_data)

    # Write results to Cosmos DB
    database = cosmos_client.get_database_client(database_name)
    container = database.get_container_client(container_name)
    container.upsert_item(results)

    # Send notification to Event Grid
    event_grid_event = EventGridEvent(
        event_type="FileProcessed",
        data=results,
        subject="BlobStorage/FileProcessing",
        event_time=event.event_time,
        data_version="1.0"
    )
    
    event_grid_client.send(event_grid_event)

def process_data(data):
    # Add data processing logic here
    return {"processed": data.decode('utf-8')}